402 |     <div id="ui-layer">
403 |         <div style="display: flex; gap: 10px; margin-bottom: 8px;">
404 |             <select id="engine-select" style="flex: 1; padding: 8px; border-radius: 4px; background: #333; color: white; border: 1px solid #007bff;">
405 |                 <option value="anthro">ENGINE: Anthropology (2026 Edition)</option>
406 |                 <option value="psych">ENGINE: General Psychology (Legacy)</option>
407 |             </select>
408 |             <button onclick="masterDraw()" style="flex: 1; margin-top: 0;">EXECUTE DRAW COMMAND</button>
