417 |     <script>
418 |         function masterDraw() {
419 |             const engine = document.getElementById('engine-select').value;
420 |             if (engine === 'psych') {
421 |                 drawPsychology();
422 |             } else if (engine === 'anthro') {
423 |                 drawAnthropology();
424 |             }
425 |         }
426 | 
427 |         function drawAnthropology() {
428 |             const raw = document.getElementById('json-pen').value;
429 |             const container = document.getElementById('document-container');
430 |             
431 |             try {
432 |                 const doc = JSON.parse(raw);
433 |                 container.innerHTML = '';
434 |                 const availableWidth = window.innerWidth - 20;
435 |                 const scale = availableWidth < 794 ? availableWidth / 794 : 1;
436 | 
437 |                 Object.keys(doc).forEach(pageKey => {
438 |                     const pageData = doc[pageKey];
439 |                     const wrapper = document.createElement('div');
440 |                     wrapper.className = 'page-wrapper';
441 |                     wrapper.style.marginTop = '20px';
442 | 
443 |                     const pageDiv = document.createElement('div');
444 |                     pageDiv.className = 'page-canvas';
445 |                     pageDiv.style.transform = `scale(${scale})`;
446 |                     pageDiv.id = `page-${pageKey}`;
447 | 
448 |                     if (pageData.requires_manual_image === true) {
449 |                         const flag = document.createElement('div');
450 |                         flag.className = 'manual-flag';
451 |                         flag.innerText = '🖼️ MANUAL IMAGE REQUIRED';
452 |                         pageDiv.appendChild(flag);
453 |                     }
454 | 
455 |                     pageData.content.forEach(item => {
456 |                         const element = document.createElement('div');
457 | 
458 |                         if (item.type === 'unit-header') {
459 |                             element.className = 'anthro-unit-header';
460 |                             element.innerHTML = `<span class="anthro-unit-label">Unit ${item.number || ''}</span><span class="anthro-unit-title">${item.title || ''}</span><span class="anthro-unit-hours">Study Hours: ${item.hours || ''}</span>`;
461 |                         }
462 |                         else if (item.type === 'callout-box') {
463 |                             element.className = 'anthro-callout';
464 |                             const iconFile = item.icon === 'books' ? 'icon-books.png' : 'icon-question-man.png';
465 |                             let listHtml = '';
466 |                             if (item.items) {
467 |                                 listHtml = '<div class="anthro-list">' + 
468 |                                     item.items.map(i => `
469 |                                         <div class="anthro-list-item">
470 |                                             <img src="assets/bullet-swirl.png" class="anthro-bullet-img">
471 |                                             <div>${i}</div>
472 |                                         </div>`).join('') + 
473 |                                     '</div>';
474 |                             }
475 |                             element.innerHTML = `
476 |                                 <div class="anthro-callout-icon"><img src="assets/${iconFile}"></div>
477 |                                 <div class="anthro-callout-content">
478 |                                     <span class="anthro-callout-title">${item.label || ''}</span>
479 |                                     ${item.body || ''}
480 |                                     ${listHtml}
481 |                                 </div>`;
482 |                         }
483 |                         else if (item.type === 'bullet-list') {
484 |                             element.className = 'anthro-list';
485 |                             const listItems = item.items || [];
486 |                             listItems.forEach(text => {
487 |                                 const row = document.createElement('div');
488 |                                 row.className = 'anthro-list-item';
489 |                                 
490 |                                 let bImg = 'bullet-swirl.png'; // Default
491 |                                 if (item.bullet === 'spark') bImg = 'bullet-spark.png';
492 |                                 if (item.bullet === 'checkmark') bImg = 'bullet-check.png';
493 |                                 
494 |                                 if (item.bullet === 'char') {
495 |                                     row.innerHTML = `<div class="anthro-bullet-char">${item.char || '•'}</div><div>${text}</div>`;
496 |                                 } else {
497 |                                     row.innerHTML = `<img src="assets/${bImg}" class="anthro-bullet-img"><div>${text}</div>`;
498 |                                 }
499 |                                 element.appendChild(row);
500 |                             });
501 |                         }
502 |                         else if (item.type === 'anthro-toc') {
503 |                             element.innerHTML = item.items.map(i => `
504 |                                 <div class="anthro-toc-item anthro-toc-level-${i.level || 0}">
505 |                                     <span>${i.text}</span>
506 |                                     <div class="anthro-toc-dots"></div>
507 |                                     <span class="anthro-toc-page">${i.page}</span>
508 |                                 </div>
509 |                             `).join('');
510 |                         }
511 |                         else if (item.type === 'title-block') {
512 |                             element.className = 'anthro-title-block';
513 |                             element.innerHTML = `
514 |                                 <div class="anthro-title-sub">${item.top || ''}</div>
515 |                                 <div class="anthro-title-main">${item.main || ''}</div>
516 |                                 <div class="anthro-title-sub">${item.bottom || ''}</div>
517 |                             `;
518 |                         }
519 |                         else if (item.type === 'graphic') {
520 |                             element.className = 'graphic-container';
521 |                             element.innerHTML = `${item.svgCode}${item.caption ? `<div class="graphic-caption">${item.caption}</div>` : ''}`;
522 |                         }
523 |                         else if (item.type === 'paragraph') {
524 |                             element.className = 'p-block';
525 |                             element.innerHTML = item.body;
526 |                         }
527 |                         else if (item.type === 'header') {
528 |                             element.className = 'h-block';
529 |                             element.innerHTML = item.body;
530 |                         }
531 |                         else if (item.type === 'table') {
532 |                             let t = '<table>';
533 |                             item.rows.forEach((row, idx) => {
534 |                                 const isHeader = idx === 0 && item.headerStyle;
535 |                                 const tdClass = isHeader ? 'class="anthro-table-header"' : '';
536 |                                 t += '<tr>' + row.map(c => `<td ${tdClass}>${c}</td>`).join('') + '</tr>';
537 |                             });
538 |                             element.innerHTML = t + '</table>';
539 |                         }
540 |                         else if (item.type === 'reference-item') {
541 |                             element.className = 'anthro-reference';
542 |                             element.innerHTML = item.body;
543 |                         }
544 |                         else if (item.type === 'term-header') {
545 |                             element.className = 'anthro-term';
546 |                             element.innerText = item.body;
547 |                         }
548 |                         else if (item.type === 'kv-list') {
549 |                             element.className = 'anthro-kv-container';
550 |                             element.innerHTML = item.items.map(row => `
551 |                                 <div class="anthro-kv-row">
552 |                                     <div class="anthro-kv-label">${row.label}</div>
553 |                                     <div class="anthro-kv-separator">:</div>
554 |                                     <div class="anthro-kv-value">${row.value}</div>
555 |                                 </div>
556 |                             `).join('');
557 |                         }
558 |                         else if (item.type === 'footnote') {
559 |                             element.className = 'anthro-footnote';
560 |                             element.innerHTML = `<sup>${item.number || ''}</sup> ${item.body}`;
561 |                         }
562 |                         else if (item.type === 'spacer') {
563 |                             element.style.flexGrow = item.flex || '0';
564 |                             element.style.height = item.height || '0px';
565 |                         }
566 |                         else if (item.type === 'footer') {
567 |                             element.className = 'footer';
568 |                             element.innerText = item.val;
569 |                         }
570 | 
