            wrapper.className = 'page-wrapper';
            wrapper.style.marginTop = '20px';

            const pageDiv = document.createElement('div');
            pageDiv.className = 'page-canvas';
            pageDiv.style.transform = `scale(${scale})`;
            pageDiv.id = `page-${pageKey}`;

            pageData.content.forEach(item => {
                const element = document.createElement('div');

                if (item.type === 'logic-header') {
                    element.className = 'logic-header';
                }
                else if (item.type === 'logic-footer') {
                    element.className = 'logic-footer';
                    element.innerHTML = `<span>${item.authors || ''}</span><span>Page ${item.page || pageKey}</span>`;
                }
                else if (item.type === 'chapter-title') {
                    element.innerHTML = `<span class="logic-chapter-num">CHAPTER ${item.number}</span><span class="logic-chapter-title">${item.title}</span>`;
