                pageDiv.appendChild(element);
            });
            wrapper.appendChild(pageDiv);
            container.appendChild(wrapper);
        });
        window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) { alert("Logic Engine Error: " + err); }
}

